// @ts-nocheck
/*
仕様:
  リズム系テストツールで使うCanvasパーティクル生成ユーティリティ。

役割:
  - 判定スパークと伴奏者リアクションのパーティクル配列を作る。
  - 呼び出し側は描画・寿命更新だけを担当する。
*/

export function appendSparkParticles(particles, x, y, color) {
    particles.push({
        x, y,
        type: "ring",
        color,
        alpha: 1,
        decay: 0.05,
        size: 10,
        targetSize: 80
    });

    for (let i = 0; i < 8; i++) {
        const angle = Math.PI * 2 * (i / 8) + Math.random() * 0.22;
        const dist = 30 + Math.random() * 74;
        const speed = dist / 0.5;
        particles.push({
            x, y,
            type: "text",
            vx: Math.cos(angle) * speed,
            vy: Math.sin(angle) * speed,
            color,
            alpha: 1,
            decay: 0.03,
            size: 6 + Math.random() * 8,
            char: ["✦", "＊", "✧"][Math.floor(Math.random() * 3)],
            rot: Math.random() * 360,
            vrot: (Math.random() - 0.5) * 10
        });
    }
}

export function appendCompanionParticles(particles, x, y, color, char = "", strong = false) {
    const count = strong ? 8 : 4;
    const baseAngle = -Math.PI / 2;
    const spread = 120 * Math.PI / 180;
    const lift = strong ? 200 : 120;
    for (let i = 0; i < count; i++) {
        const angle = baseAngle + (Math.random() - 0.5) * spread;
        const dist = lift * (0.48 + Math.random() * 0.7);
        const speed = dist / 0.8;
        particles.push({
            x: x + (Math.random() - 0.5) * 34,
            y: y + (Math.random() - 0.5) * 22,
            type: "text",
            vx: Math.cos(angle) * speed + (Math.random() - 0.5) * 40,
            vy: Math.sin(angle) * speed,
            color,
            alpha: 1,
            decay: strong ? 0.012 : 0.016,
            size: (strong ? 28 : 22) + Math.random() * 8,
            char,
            rot: Math.random() * 360,
            vrot: (Math.random() - 0.5) * 5
        });
    }
}
